output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?duration WHERE {
  VALUES ?year {
    1982 2013
  }
  ?series wdt:P31 wd:Q4739182 ; wdt:P585 ?date .
  FILTER(YEAR(?date) = ?year)
  ?game wdt:P548 ?series ; wdt:P2141 ?duration
}
ORDER BY ?duration
LIMIT 1
OFFSET 2

